questions.questionText:
What is the output of this code?

List<String> list = new ArrayList<>();
list.add("a");
list.add("b");
list.add(1, "c");
System.out.println(list);

What does this code output?

Set<Integer> s = new HashSet<>();
s.add(1); s.add(2); s.add(1); s.add(3);
System.out.println(s.size());

What is the output of this code?

Map<String, Integer> m = new LinkedHashMap<>();
m.put("dog", 1);
m.put("cat", 2);
m.put("bird", 3);
m.forEach((k, v) -> System.out.print(k + v));
System.out.println();
m.replace("cat", 20);
m.forEach((k, v) -> System.out.print(k + v));

What is the output of this code?

TreeSet<Integer> ts = new TreeSet<>(Comparator.reverseOrder());
ts.add(5); ts.add(1); ts.add(3); ts.add(2);
System.out.println(ts.lower(3));
System.out.println(ts.higher(3));

What is the output of this code?

Deque<Integer> d = new ArrayDeque<>();
d.addFirst(1); d.addLast(2);
d.push(3);
System.out.println(d.pollFirst());
System.out.println(d.pollLast());
System.out.println(d.size());

What is the output of this code?

List<String> list = Arrays.asList("c", "b", "a");
Collections.sort(list, Collections.reverseOrder());
int idx = Collections.binarySearch(list, "b");
System.out.println(idx);

What is the output of this code?

Map<Integer, String> map = new HashMap<>();
map.put(1, "one");
map.putIfAbsent(1, "ONE");
map.computeIfAbsent(2, k -> "TWO");
map.forEach((k, v) -> System.out.print(k + "=" + v + " "));
System.out.println();
System.out.println(map.getOrDefault(3, "not found"));

What is the output of this code?

NavigableMap<Integer, String> nm = new TreeMap<>();
nm.put(10, "ten"); nm.put(20, "twenty"); nm.put(30, "thirty");
System.out.println(nm.subMap(10, true, 30, false));
System.out.println(nm.lowerKey(25));
System.out.println(nm.ceilingKey(25));

What is the output of this code?

List<Integer> a = new ArrayList<>(Arrays.asList(1, 2, 3));
List<Integer> b = new ArrayList<>(Arrays.asList(4, 5, 6));
Collections.rotate(a, 1);
Collections.rotate(b, -1);
System.out.println(a);
System.out.println(b);
Collections.swap(a, 0, a.size() - 1);
System.out.println(a);

What is the output of this code?

Map<String, Integer> m = new IdentityHashMap<>();
m.put(new String("key"), 1);
m.put(new String("key"), 2);
m.put("key", 3);
m.put("key", 4);
System.out.println(m.size());

What is the output of this code?

List<String> list = new CopyOnWriteArrayList<>();
list.add("a"); list.add("b"); list.add("c");
for (String s : list) {
    if ("b".equals(s)) list.remove(s);
    System.out.print(s + " ");
}
System.out.println();
System.out.println(list);

What is the output?

Map<String, Integer> m = new TreeMap<>();
m.put("c", 3); m.put("a", 1); m.put("b", 2);
System.out.println(m.firstKey());
System.out.println(m.lastEntry().getValue());
System.out.println(m.subMap("a", "c").size());

What is the output?

List<Integer> list = new ArrayList<>(Arrays.asList(1, 2, 3, 4, 5));
ListIterator<Integer> it = list.listIterator();
while (it.hasNext()) {
    int x = it.next();
    if (x == 3) {
        it.remove();
        it.add(30);
    }
}
System.out.println(list);

What is the output?

Deque<Integer> d = new LinkedList<>();
d.offerFirst(1); d.offerLast(2);
d.push(3); // push is same as addFirst
d.addLast(4);
System.out.println(d.pollFirst());
System.out.println(d.pollLast());
System.out.println(d);
